examples.bad:
weak var authCoordinator: AuthenticationCoordinator?

func onPinEntered(_ pin: String) {
    authCoordinator!.verifyAndSubmit(pin: pin)
}

examples.good:
weak var authCoordinator: AuthenticationCoordinator?

func onPinEntered(_ pin: String) {
    guard let coordinator = authCoordinator else {
        assertionFailure("Authentication coordinator was deallocated prematurely.")
        return
    }
    coordinator.verifyAndSubmit(pin: pin)
}
